VALUES
  ('police-3218f787-moex-00027', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法與增修條文之現行規定，有關公務人員選拔，下列敘述何者正確？', '["公務人員之選拔，應以實作方式考選，以確保任用優秀人才", "公務人員之選拔，應按省（直轄市）分定名額，分區考試", "公務人員之選拔，應經公開考試，方得任用", "公務人員之選拔，應依年齡分布，任用一定比例之青年 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00028', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於審計長，下列敘述何者正確？', '["由總統逕自任命之", "不受任期保障", "應於行政院提出決算後於期限內完成審核，並提出審核報告於立法院", "立法院委員會審議決算報告時，有至立法院備詢之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00029', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法訴訟法規定，有關法庭之友之敘述，下列何者正確？', '["法庭之友制度，乃沿用司法院大法官審理案件法中已存之制度", "案件之關聯性，應包含情感上的關聯性", "依裁定許可提出專業意見或資料時，無需揭露與當事人間之關係", "人民向憲法法庭聲請擔任法庭之友時，應委任代理人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00030', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於訴訟權的限制，下列敘述何者錯誤？', '["不得以經濟利益，限制上訴", "不得以身分，限制訴訟權之行使", "得設再審不變期間之限制", "得設上訴期間之限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00031', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法及相關法律規定，關於國家賠償，下列敘述何者正確？', '["國家賠償乃是基於填補人民之特別犧牲而生的責任", "國家補償係針對國家無過失造成的損害，國家賠償則僅限於國家有過失所造成之損害", "憲法第 24 條關於公務員違法導致損害應負賠償責任，未規定以故意過失為要件，故屬於 無過失責任", "國家對公務員之求償，限於具故意或重大過失之情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00032', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '特別公課是指國家為一定政策目標之需要，對於有特定關係之國民所課徵之公法上負擔，將 課徵所得之金錢，以建立特別基金，專供特定目標達成，有專款專用之意旨。依上述說明， 下列何者屬於特別公課？', '["空氣污染防制費", "貨物稅", "全民健康保險費", "國家考試報名費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00033', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '有關一般行為自由之保障範圍，不包括下列何者？', '["與非配偶從事性行為之性自主權", "人民隨時任意前往他方或停留一定處所之行動自由", "一般人民駕駛汽車之自由", "人民依其意志作為或不作為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00034', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文規定，關於總統解散立法院，下列敘述何者正確？', '["總統上任後，如所屬政黨在國會席次未過半，可藉由主動解散立法院改選立委，尋求最新 民意的支持", "立法院解散後應於60日內舉行立法委員選舉，並於選舉結果確認後10日內自行集會", "為即時因應政治困局，縱使於戒嚴或緊急命令生效期間，總統亦可解散立法院", "總統宣告解散立法院前應向司法院院長進行諮詢，以確保此一解散決定的合憲性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00035', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院釋字第613號解釋，有關獨立機關，下列敘述何者錯誤？', '["憲法規定行政院為國家最高行政機關，基於行政一體原則，須為包括獨立機關在內之所有 行政院所屬機關之整體施政表現負責", "獨立機關可以依據法律，排除上級機關於層級式行政體制下，對具體個案決定之指揮與監 督，不受政治干擾、可專業自主決定", "基於責任政治以及行政一體原則，行政院院長遇有更迭時，獨立機關之委員也應該與行政 院院長一同辭職，以符合民主正當性", "獨立機關之人選與其施政良窳有密切關係，故行政院應擁有對獨立機關重要人事一定之決 定權限，以落實行政一體及責任政治 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00036', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文規定，關於立法院立法委員之選舉，下列敘述何者錯誤？', '["任期4年，連選得連任", "由地區直轄市、縣市選舉出 73 人，依各其人口比例分配，並按應選名額劃分同額選舉區 選出之", "全國不分區及僑居國外國民共34人，依政黨名單投票選舉之，由獲得5%以上政黨選舉票 之政黨依得票比率選出之", "各政黨當選名單中，婦女不得低於三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
